// ========== AUTHENTICATION CONFIG ==========
const AUTH_CONFIG = {
  u: 'JS01',
  p: 'Jseeds',
  key: 'jseeds_auth_success'
};

function checkAuth() {
  const overlay = document.getElementById('login-overlay');
  const mainContent = document.getElementById('main-content');
  if (sessionStorage.getItem(AUTH_CONFIG.key) === 'true') {
    overlay.style.display = 'none';
    mainContent.style.display = 'block';
    return true;
  }
  return false;
}

function handleLogin() {
  const uInput = document.getElementById('username');
  const pInput = document.getElementById('password');
  const errorMsg = document.getElementById('login-error');
  const btn = document.getElementById('login-btn');
  const mainContent = document.getElementById('main-content');

  if (uInput.value === AUTH_CONFIG.u && pInput.value === AUTH_CONFIG.p) {
    sessionStorage.setItem(AUTH_CONFIG.key, 'true');
    const overlay = document.getElementById('login-overlay');
    overlay.classList.add('hidden');
    
    // Aesthetic feedback
    btn.textContent = "Access Granted...";
    btn.style.background = "#28a745";
    
    setTimeout(() => {
      overlay.style.display = 'none';
      mainContent.style.display = 'block';
      // Initialize the site since they just logged in
      initMainSite();
    }, 800);
  } else {
    errorMsg.textContent = "Invalid Scholar ID or Sacred Word.";
    pInput.value = "";
    pInput.focus();
    
    // Shake animation
    const card = document.querySelector('.login-card');
    card.style.animation = 'none';
    void card.offsetWidth; // Trigger reflow
    card.style.animation = 'shake 0.4s ease-in-out';
  }
}

// Add shake animation to styles dynamically if needed, 
// but for now I'll just handle the basics.

