// ========== SEARCH & MAP DATA ==========
const mapData = {
  eden: {
    title: 'Garden of Eden',
    tamil: 'ஏதேன் தோட்டம்',
    desc: 'The beginning of God\'s interaction with humanity. Humanity\'s origins and the first covenant were established here.',
    books: ['Genesis']
  },
  egypt: {
    title: 'Egypt',
    tamil: 'எகிப்து',
    desc: 'The house of bondage where Israel grew into a nation. The site of the first Passover and the Great Exodus.',
    books: ['Genesis', 'Exodus']
  },
  sinai: {
    title: 'Mount Sinai',
    tamil: 'சீனாய் மலை',
    desc: 'Where God spoke to Moses and gave the Ten Commandments. The birthplace of the Law and the Tabernacle.',
    books: ['Exodus', 'Leviticus', 'Numbers', 'Deuteronomy']
  },
  jericho: {
    title: 'Jericho',
    tamil: 'எரிகோ',
    desc: 'The first victory in the Promised Land. The walls fell by faith, marking the beginning of the conquest of Canaan.',
    books: ['Joshua']
  },
  babylon: {
    title: 'Babylonia',
    tamil: 'பாபிலோனியா',
    desc: 'The place of exile where the Israelites were taken captive. Many prophets spoke here of a future restoration.',
    books: ['2 Kings', 'Ezra', 'Daniel', 'Ezekiel']
  }
};


// ========== STATE ==========
let currentCategory = 'law';
let searchQuery = '';
let completedBooks = JSON.parse(localStorage.getItem('ot_completed_books')) || [];


// ========== DOM READY ==========
document.addEventListener('DOMContentLoaded', () => {
  if (checkAuth()) {
    initMainSite();
  } else {
    initAuthListeners();
  }
});

function initAuthListeners() {
  const btn = document.getElementById('login-btn');
  const pInput = document.getElementById('password');
  
  btn?.addEventListener('click', handleLogin);
  pInput?.addEventListener('keypress', (e) => {
    if (e.key === 'Enter') handleLogin();
  });
}

function initMainSite() {
  createParticles();
  initNavbar();
  initTimeline();
  initTabs();
  renderBooks('law');
  initSearch();
  initRevealAnimations();
  initModal();
  updateProgressBar();
}

// ========== SEARCH ==========
function initSearch() {
  const searchInput = document.getElementById('book-search');
  searchInput?.addEventListener('input', (e) => {
    searchQuery = e.target.value.toLowerCase();
    renderBooks(currentCategory);
  });
}

// ========== PARTICLES ==========
function createParticles() {
  const container = document.querySelector('.hero-particles');
  if (!container) return;
  for (let i = 0; i < 30; i++) {
    const p = document.createElement('div');
    p.classList.add('particle');
    p.style.left = Math.random() * 100 + '%';
    p.style.animationDelay = Math.random() * 8 + 's';
    p.style.animationDuration = (6 + Math.random() * 6) + 's';
    p.style.width = p.style.height = (2 + Math.random() * 3) + 'px';
    container.appendChild(p);
  }
}

// ========== NAVBAR ==========
function initNavbar() {
  const navbar = document.querySelector('.navbar');
  const hamburger = document.querySelector('.hamburger');
  const navLinks = document.querySelector('.nav-links');
  window.addEventListener('scroll', () => {
    navbar.classList.toggle('scrolled', window.scrollY > 50);
  });
  hamburger?.addEventListener('click', () => {
    navLinks.classList.toggle('active');
    const spans = hamburger.querySelectorAll('span');
    hamburger.classList.toggle('open');
  });
  navLinks?.querySelectorAll('a').forEach(a => {
    a.addEventListener('click', () => navLinks.classList.remove('active'));
  });
}

// ========== TIMELINE ==========
function initTimeline() {
  document.querySelectorAll('.timeline-item').forEach(item => {
    item.addEventListener('click', () => {
      item.classList.toggle('expanded');
    });
  });
}

// ========== TABS ==========
function initTabs() {
  document.querySelectorAll('.tab-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      currentCategory = btn.dataset.category;
      renderBooks(currentCategory);
    });
  });
}

// ========== RENDER BOOKS ==========
function renderBooks(category) {
  const grid = document.getElementById('books-grid');
  if (!grid) return;
  
  const books = (booksData[category] || []).filter(b => 
    b.name.toLowerCase().includes(searchQuery) || 
    b.eng.toLowerCase().includes(searchQuery) ||
    b.author.toLowerCase().includes(searchQuery) ||
    b.theme.toLowerCase().includes(searchQuery) ||
    b.summary.toLowerCase().includes(searchQuery)
  );

  grid.innerHTML = books.length ? books.map(b => {
    const isCompleted = completedBooks.includes(b.id);
    return `
      <div class="book-card ${isCompleted ? 'completed' : ''}" data-id="${b.id}" onclick="openBookModal('${category}','${b.id}')">
        ${isCompleted ? '<div class="completed-badge"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round" style="margin-right:2px;"><polyline points="20 6 9 17 4 12"/></svg> முடிந்தது</div>' : ''}
        <div class="book-card-header">
          <div class="book-icon">${b.icon}</div>
          <h3>${b.name}<small>${b.eng}</small></h3>
        </div>
        <div class="book-meta">
          <span><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg> ${b.author}</span>
          <span><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg> ${b.date}</span>
        </div>
        <div class="book-card-body">
          <p class="book-summary">${b.summary}</p>
          <button class="book-check-btn ${isCompleted ? 'active' : ''}" onclick="toggleBookCompletion(event, '${b.id}')">
            ${isCompleted ? '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg> படித்தாயிற்று' : '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M4 19.5A2.5 2.5 0 0 1 6.5 17H20"/><path d="M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z"/></svg> படித்து முடித்தேன்'}
          </button>
        </div>
      </div>
    `;
  }).join('') : `<div class="no-results">No books found matching "${searchQuery}"</div>`;

  // Re-init reveal for new cards
  grid.querySelectorAll('.book-card').forEach((card, i) => {
    card.style.opacity = '0';
    card.style.transform = 'translateY(20px)';
    setTimeout(() => {
      card.style.transition = 'opacity 0.5s ease, transform 0.5s ease';
      card.style.opacity = '1';
      card.style.transform = 'translateY(0)';
    }, i * 60);
  });
}

// ========== PROGRESS TRACKING ==========
function toggleBookCompletion(event, bookId) {
  event.stopPropagation();
  const index = completedBooks.indexOf(bookId);
  if (index > -1) {
    completedBooks.splice(index, 1);
  } else {
    completedBooks.push(bookId);
  }
  localStorage.setItem('ot_completed_books', JSON.stringify(completedBooks));
  renderBooks(currentCategory);
  updateProgressBar();
}

function updateProgressBar() {
  const totalBooks = 39; // OT Total
  const percent = Math.round((completedBooks.length / totalBooks) * 100);
  const bar = document.getElementById('progress-bar-fill');
  const text = document.getElementById('progress-percent');
  if (bar) bar.style.width = percent + '%';
  if (text) text.textContent = percent + '%';
}

// ========== MAP INTERACTIONS ==========
function openMapDetail(locKey) {
  const loc = mapData[locKey];
  if (!loc) return;

  const placeholder = document.querySelector('.map-info-placeholder');
  const content = document.getElementById('map-info-content');
  
  if (placeholder) placeholder.style.display = 'none';
  if (content) {
    content.style.display = 'block';
    content.style.opacity = '0';
    content.style.transform = 'translateY(10px)';
    
    document.getElementById('map-loc-title').textContent = loc.title;
    document.getElementById('map-loc-tamil').textContent = loc.tamil;
    document.getElementById('map-loc-desc').textContent = loc.desc;
    
    const booksContainer = document.getElementById('map-loc-books');
    booksContainer.innerHTML = loc.books.map(b => `<span class="map-loc-tag">${b}</span>`).join('');
    
    setTimeout(() => {
      content.style.transition = 'all 0.5s ease';
      content.style.opacity = '1';
      content.style.transform = 'translateY(0)';
    }, 10);
  }
}


// ========== MODAL ==========
function initModal() {
  const overlay = document.getElementById('modal-overlay');
  const closeBtn = document.getElementById('modal-close');
  overlay?.addEventListener('click', (e) => {
    if (e.target === overlay) closeModal();
  });
  closeBtn?.addEventListener('click', closeModal);
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') closeModal();
  });
}

function openBookModal(category, id) {
  const books = booksData[category] || [];
  const book = books.find(b => b.id === id);
  if (!book) return;
  document.getElementById('modal-title').innerHTML = `${book.name}<small>${book.eng}</small>`;
  document.getElementById('modal-meta').innerHTML = `
    <div class="modal-meta-item"><strong><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="margin-right:5px; vertical-align:middle;"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg> ஆசிரியர்:</strong> ${book.author}</div>
    <div class="modal-meta-item"><strong><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="margin-right:5px; vertical-align:middle;"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg> காலம்:</strong> ${book.date}</div>
    <div class="modal-meta-item"><strong><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="margin-right:5px; vertical-align:middle;"><circle cx="12" cy="12" r="10"/><circle cx="12" cy="12" r="4"/></svg> கருத்து:</strong> ${book.theme}</div>
  `;
  document.getElementById('modal-summary').textContent = book.summary;
  document.getElementById('modal-detail').innerHTML = book.detail || '';
  const overlay = document.getElementById('modal-overlay');
  overlay.classList.add('active');
  document.body.style.overflow = 'hidden';
}

function closeModal() {
  document.getElementById('modal-overlay').classList.remove('active');
  document.body.style.overflow = '';
}

// ========== YOUTUBE INTERACTION ==========
function loadYoutubeVideo() {
  const container = document.getElementById('yt-iframe-placeholder');
  const overlay = document.querySelector('.video-overlay');
  
  if (!container || !overlay) return;

  // Add the iframe
  container.innerHTML = `
    <iframe
      src="https://www.youtube.com/embed/videoseries?list=PL9DXIMm3S_fbo1XYNGlKleSbCURlHwGwQ&autoplay=1"
      title="Old Testament Overview – Video Playlist"
      frameborder="0"
      allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
      referrerpolicy="strict-origin-when-cross-origin"
      allowfullscreen>
    </iframe>
  `;

  // Hide the overlay
  overlay.style.opacity = '0';
  setTimeout(() => {
    overlay.style.display = 'none';
  }, 500);
}

// ========== SCROLL REVEAL ==========
function initRevealAnimations() {
  const observer = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        entry.target.classList.add('visible');
      }
    });
  }, { threshold: 0.15 });
  document.querySelectorAll('.reveal, .timeline-item').forEach(el => observer.observe(el));
}
